def _aplicar_patches_resumo_mensal_regional(block_code: str) -> str:
    """Inclui abertura por regional no RESUMO MENSAL sem alterar o HTML da aba."""
    if "_regionais_para_indicador_canal" in block_code:
        return block_code

    novo_bloco_lookup = """
            def _construir_indices_lookup_canal(mapa_ref: dict):
                por_canal_indicador: dict[tuple[str, str], dict[str, float]] = {}
                total_indicador: dict[str, dict[str, float]] = {}
                for (canal_key, indicador_key, mes_key), valor in mapa_ref.items():
                    canal_norm = str(canal_key).strip()
                    indicador_norm = str(indicador_key).strip()
                    mes_norm = str(mes_key).strip().lower()
                    valor_num = float(valor or 0.0)
                    serie_canal = por_canal_indicador.setdefault((canal_norm, indicador_norm), {})
                    serie_canal[mes_norm] = serie_canal.get(mes_norm, 0.0) + valor_num
                    serie_total = total_indicador.setdefault(indicador_norm, {})
                    serie_total[mes_norm] = serie_total.get(mes_norm, 0.0) + valor_num
                return por_canal_indicador, total_indicador

            def _construir_indice_lookup_regional(mapa_ref: dict):
                por_canal_regional_indicador: dict[tuple[str, str, str], dict[str, float]] = {}
                for (canal_key, regional_key, indicador_key, mes_key), valor in mapa_ref.items():
                    chave_ref = (
                        str(canal_key).strip(),
                        str(regional_key).strip().upper(),
                        str(indicador_key).strip(),
                    )
                    mes_norm = str(mes_key).strip().lower()
                    serie_ref = por_canal_regional_indicador.setdefault(chave_ref, {})
                    serie_ref[mes_norm] = serie_ref.get(mes_norm, 0.0) + float(valor or 0.0)
                return por_canal_regional_indicador

            _indices_lookup_canal = {
                id(mapa_real): _construir_indices_lookup_canal(mapa_real),
                id(mapa_tend): _construir_indices_lookup_canal(mapa_tend),
                id(mapa_meta): _construir_indices_lookup_canal(mapa_meta),
            }
            _indices_lookup_regional = {
                id(mapa_real_regional): _construir_indice_lookup_regional(mapa_real_regional),
                id(mapa_tend_regional): _construir_indice_lookup_regional(mapa_tend_regional),
                id(mapa_meta_regional): _construir_indice_lookup_regional(mapa_meta_regional),
            }

            def _lookup_indicador(mapa_ref: dict, indicador_ref: str, canais_ref: list[str] | None = None, canal_ref: str | None = None) -> dict[str, float]:
                indices_ref = _indices_lookup_canal.get(id(mapa_ref))
                if indices_ref is None:
                    indices_ref = _construir_indices_lookup_canal(mapa_ref)
                    _indices_lookup_canal[id(mapa_ref)] = indices_ref
                por_canal_ref, total_ref = indices_ref
                indicador_norm = str(indicador_ref).strip()
                canais_set = {str(c).strip() for c in canais_ref} if canais_ref is not None else None
                if canal_ref is not None:
                    canal_norm = str(canal_ref).strip()
                    if canais_set is not None and canal_norm not in canais_set:
                        return {}
                    return dict(por_canal_ref.get((canal_norm, indicador_norm), {}))
                if canais_set is None:
                    return dict(total_ref.get(indicador_norm, {}))
                saida: dict[str, float] = {}
                for canal_norm in canais_set:
                    for mes_norm, valor_num in por_canal_ref.get((canal_norm, indicador_norm), {}).items():
                        saida[mes_norm] = saida.get(mes_norm, 0.0) + valor_num
                return saida

            def _lookup_indicador_regional(mapa_ref: dict, indicador_ref: str, canal_ref: str, regional_ref: str) -> dict[str, float]:
                indice_ref = _indices_lookup_regional.get(id(mapa_ref))
                if indice_ref is None:
                    indice_ref = _construir_indice_lookup_regional(mapa_ref)
                    _indices_lookup_regional[id(mapa_ref)] = indice_ref
                chave_ref = (
                    str(canal_ref).strip(),
                    str(regional_ref).strip().upper(),
                    str(indicador_ref).strip(),
                )
                return dict(indice_ref.get(chave_ref, {}))

            _atividade_regional: dict[tuple[str, str], dict[str, float]] = {}
            if not agg_metricas_regional.empty:
                for canal_ref, regional_ref, indicador_ref, qtde_ref, tend_ref, meta_ref in agg_metricas_regional[
                    ['CANAL_PLAN', 'REGIONAL', 'INDICADOR', 'QTDE', 'TEND_QTD', 'DESAFIO_QTD']
                ].itertuples(index=False, name=None):
                    canal_norm = str(canal_ref).strip()
                    regional_norm = str(regional_ref).strip().upper()
                    indicador_norm = str(indicador_ref).strip()
                    total_ref = sum(
                        float(valor_ref) if pd.notna(valor_ref) else 0.0
                        for valor_ref in (qtde_ref, tend_ref, meta_ref)
                    )
                    chave_ref = (canal_norm, indicador_norm)
                    regionais_ref = _atividade_regional.setdefault(chave_ref, {})
                    regionais_ref[regional_norm] = regionais_ref.get(regional_norm, 0.0) + total_ref

            def _regionais_para_indicador_canal(indicador_ref: str, canal_ref: str) -> list[str]:
                canal_norm = str(canal_ref).strip()
                indicador_norm = str(indicador_ref).strip()
                indicadores_busca_ref = (
                    ['VENDA BRUTA', 'ATIVADOS']
                    if indicador_norm.upper() == 'FAKE'
                    else [indicador_norm]
                )
                regionais_set: set[str] = set()
                for indicador_busca_ref in indicadores_busca_ref:
                    regionais_set.update(
                        regional_ref
                        for regional_ref, total_ref in _atividade_regional.get(
                            (canal_norm, indicador_busca_ref), {}
                        ).items()
                        if total_ref > 0
                    )
                ranking_ref: list[tuple[str, float]] = []
                for regional_ref in regionais_set:
                    lookup_real_ref = _lookup_indicador_regional(mapa_real_regional, indicador_norm, canal_norm, regional_ref)
                    lookup_tend_ref = _lookup_indicador_regional(mapa_tend_regional, indicador_norm, canal_norm, regional_ref)
                    metricas_ref = calcular_yoy_ytd_mensal_lookup(
                        lookup_real_ref,
                        lookup_tend_ref,
                        mes_foco_ref,
                        mes_corrente_local
                    )
                    ranking_ref.append((regional_ref, float(metricas_ref.get('YTD26', 0.0) or 0.0)))
                return [
                    regional_ref
                    for regional_ref, _ in sorted(ranking_ref, key=lambda item: (-item[1], item[0]))
                ]

            def _slug_resumo_mensal(*partes_ref) -> str:
                texto_ref = "_".join(str(parte) for parte in partes_ref if str(parte).strip())
                texto_ref = unicodedata.normalize("NFKD", texto_ref).encode("ASCII", "ignore").decode("ASCII")
                texto_ref = re.sub(r"[^A-Za-z0-9]+", "_", texto_ref).strip("_").lower()
                return texto_ref or "item"

            def _montar_linha(
                canal_rotulo: str,
                indicador_ref: str,
                canais_total_ref: list[str] | None = None,
                canal_lookup_ref: str | None = None,
                regional_lookup_ref: str | None = None,
                nivel_ref: str = "canal",
                parent_key_ref: str = "",
                row_key_ref: str = "",
                has_children_ref: bool = False
            ) -> dict:
                if regional_lookup_ref:
                    canal_base_ref = canal_lookup_ref or canal_rotulo
                    lookup_real = _lookup_indicador_regional(mapa_real_regional, indicador_ref, canal_base_ref, regional_lookup_ref)
                    lookup_tend = _lookup_indicador_regional(mapa_tend_regional, indicador_ref, canal_base_ref, regional_lookup_ref)
                    lookup_meta = _lookup_indicador_regional(mapa_meta_regional, indicador_ref, canal_base_ref, regional_lookup_ref)
                else:
                    lookup_real = _lookup_indicador(mapa_real, indicador_ref, canais_total_ref, canal_lookup_ref)
                    lookup_tend = _lookup_indicador(mapa_tend, indicador_ref, canais_total_ref, canal_lookup_ref)
                    lookup_meta = _lookup_indicador(mapa_meta, indicador_ref, canais_total_ref, canal_lookup_ref)

                valor_foco = obter_valor_serie_mensal_mes(mes_foco_ref, mes_foco_ref, mes_corrente_local, lookup_real, lookup_tend)
                valor_m1 = float(lookup_real.get(mes_m1_local, 0.0))
                dias_du_foco = obter_dias_uteis_corporativos(mes_foco_ref, produto_norm_ref, indicador_ref)
                dias_du_m1 = obter_dias_uteis_corporativos(mes_m1_local, produto_norm_ref, indicador_ref)
                media_du_foco = (float(valor_foco) / float(dias_du_foco)) if dias_du_foco > 0 else 0.0
                media_du_m1 = (float(valor_m1) / float(dias_du_m1)) if dias_du_m1 > 0 else 0.0
                mom_du = calcular_variacao_percentual(media_du_foco, media_du_m1) if media_du_m1 > 0 else 0.0
                orc_mes = float(lookup_meta.get(str(mes_foco_ref).strip().lower(), 0.0) or 0.0)
                tend_vs_orc_mes = calcular_variacao_percentual(valor_foco, orc_mes) if orc_mes > 0 else 0.0
                metricas = calcular_yoy_ytd_mensal_lookup(
                    lookup_real,
                    lookup_tend,
                    mes_foco_ref,
                    mes_corrente_local,
                    lookup_orc=lookup_meta
                )
                ytd_orc_valor = metricas.get('YTD_ORÇ', metricas.get('YTD_ORC', 0.0))
                ytd_vs_orc_valor = metricas.get('YTD26 vs YTD_ORÇ', metricas.get('YTD26 vs YTD_ORC', 0.0))
                linha = {'CANAL': canal_rotulo}
                for mes_col in meses_janela:
                    linha[mes_col] = obter_valor_serie_mensal_mes(
                        mes_col,
                        mes_foco_ref,
                        mes_corrente_local,
                        lookup_real,
                        lookup_tend
                    )
                linha.update({
                    'MoM': calcular_variacao_percentual(valor_foco, valor_m1),
                    'MoM D.U.': mom_du,
                    'YoY': metricas.get('YOY', 0.0),
                    'ORC': orc_mes,
                    'TEND vs ORC': tend_vs_orc_mes,
                    'YTD25': metricas.get('YTD25', 0.0),
                    'YTD26': metricas.get('YTD26', 0.0),
                    'YTD_ORÇ': ytd_orc_valor,
                    'YTD26 vs YTD25': metricas.get('YTD26 vs YTD25', 0.0),
                    'YTD26 vs YTD_ORÇ': ytd_vs_orc_valor,
                    '__NIVEL': nivel_ref,
                    '__PARENT': parent_key_ref,
                    '__ROWKEY': row_key_ref or _slug_resumo_mensal(produto_norm_ref, indicador_ref, canal_rotulo, regional_lookup_ref or ""),
                    '__HAS_CHILDREN': '1' if has_children_ref else '',
                    '__REGIONAL': str(regional_lookup_ref or '').strip().upper(),
                })
                return linha

            linhas_num = []
            indicadores_resumo_ref = ['DEMANDA', 'VENDA BRUTA']
            if produto_norm_ref == 'CONTA':
                indicadores_resumo_ref.append('FAKE')
            indicadores_resumo_ref.append('ATIVADOS')
            for indicador_ref in indicadores_resumo_ref:
                canais_secao = _canais_para_indicador(indicador_ref)
                if not canais_secao:
                    continue
                linhas_num.append(_montar_linha(
                    indicador_ref,
                    indicador_ref,
                    canais_total_ref=canais_secao,
                    nivel_ref='grupo',
                    row_key_ref=_slug_resumo_mensal(produto_norm_ref, indicador_ref, 'grupo')
                ))
                for canal_ref in canais_secao:
                    regionais_canal = _regionais_para_indicador_canal(indicador_ref, canal_ref)
                    row_key_ref = _slug_resumo_mensal(produto_norm_ref, indicador_ref, canal_ref)
                    linhas_num.append(_montar_linha(
                        canal_ref,
                        indicador_ref,
                        canal_lookup_ref=canal_ref,
                        nivel_ref='canal',
                        row_key_ref=row_key_ref,
                        has_children_ref=bool(regionais_canal)
                    ))
                    for regional_ref in regionais_canal:
                        linhas_num.append(_montar_linha(
                            regional_ref,
                            indicador_ref,
                            canal_lookup_ref=canal_ref,
                            regional_lookup_ref=regional_ref,
                            nivel_ref='regional',
                            parent_key_ref=row_key_ref,
                            row_key_ref=_slug_resumo_mensal(produto_norm_ref, indicador_ref, canal_ref, regional_ref)
                        ))
""".splitlines()

    linhas = block_code.splitlines()
    saida: list[str] = []
    i = 0
    while i < len(linhas):
        linha = linhas[i]
        stripped = linha.strip()

        if stripped == "df_mes['CANAL_PLAN'] = df_mes['CANAL_PLAN'].astype(str).str.strip()":
            saida.append(linha)
            saida.extend([
                "            if 'REGIONAL' not in df_mes.columns:",
                "                df_mes['REGIONAL'] = ''",
                "            df_mes['REGIONAL'] = df_mes['REGIONAL'].astype(str).str.strip().str[:3].str.upper()",
            ])
            i += 1
            continue

        if stripped == "partes_metricas.append(df_lig[['CANAL_PLAN', 'COD_PLATAFORMA', 'DSC_INDICADOR', 'dat_tratada', 'QTDE', 'TEND_QTD', 'DESAFIO_QTD', 'mes_ano', 'INDICADOR']].copy())":
            saida.extend([
                "                    if 'REGIONAL' not in df_lig.columns:",
                "                        df_lig['REGIONAL'] = ''",
                "                    df_lig['REGIONAL'] = df_lig['REGIONAL'].astype(str).str.strip().str[:3].str.upper()",
                "                    partes_metricas.append(df_lig[['CANAL_PLAN', 'COD_PLATAFORMA', 'DSC_INDICADOR', 'dat_tratada', 'QTDE', 'TEND_QTD', 'DESAFIO_QTD', 'mes_ano', 'INDICADOR', 'REGIONAL']].copy())",
            ])
            i += 1
            continue

        if stripped == "df_metricas = pd.concat(partes_metricas, ignore_index=True, copy=False)":
            saida.append(linha)
            saida.extend([
                "            if 'REGIONAL' not in df_metricas.columns:",
                "                df_metricas['REGIONAL'] = ''",
                "            df_metricas['REGIONAL'] = df_metricas['REGIONAL'].astype(str).str.strip().str[:3].str.upper()",
            ])
            i += 1
            continue

        if stripped == "def _ratio_vb_ativado_para_meta(canal_ref: str, mes_ref: str) -> float:":
            saida.extend("""
            agg_metricas_regional = (
                df_metricas.groupby(['CANAL_PLAN', 'REGIONAL', 'INDICADOR', 'mes_ano'], as_index=False, observed=True)[['QTDE', 'TEND_QTD', 'DESAFIO_QTD']]
                .sum()
            )
            mapa_real_regional = {
                (str(row['CANAL_PLAN']).strip(), str(row['REGIONAL']).strip().upper(), str(row['INDICADOR']).strip(), str(row['mes_ano']).strip().lower()): float(row['QTDE'] or 0.0)
                for _, row in agg_metricas_regional.iterrows()
            }
            mapa_tend_regional = {
                (str(row['CANAL_PLAN']).strip(), str(row['REGIONAL']).strip().upper(), str(row['INDICADOR']).strip(), str(row['mes_ano']).strip().lower()): float(row['TEND_QTD'] or 0.0)
                for _, row in agg_metricas_regional.iterrows()
            }
            mapa_meta_regional = {
                (str(row['CANAL_PLAN']).strip(), str(row['REGIONAL']).strip().upper(), str(row['INDICADOR']).strip(), str(row['mes_ano']).strip().lower()): float(row['DESAFIO_QTD'] or 0.0)
                for _, row in agg_metricas_regional.iterrows()
            }
""".splitlines())
            saida.append(linha)
            i += 1
            continue

        if stripped == "canais_demanda_padrao = ['Televendas Receptivo', 'E-Commerce']":
            saida.extend("""
            def _ratio_vb_ativado_regional_para_meta(canal_ref: str, regional_ref: str, mes_ref: str) -> float:
                canal_norm = str(canal_ref).strip()
                regional_norm = str(regional_ref).strip().upper()
                mes_norm = str(mes_ref).strip().lower()
                vb_ref = float(mapa_real_regional.get((canal_norm, regional_norm, 'VENDA BRUTA', mes_norm), 0.0) or 0.0)
                ativ_ref = float(mapa_real_regional.get((canal_norm, regional_norm, 'ATIVADOS', mes_norm), 0.0) or 0.0)
                if vb_ref > 0 and ativ_ref > 0:
                    return ativ_ref / vb_ref
                return _ratio_vb_ativado_para_meta(canal_norm, mes_norm)

            canais_meses_meta_regional = {
                (canal_ref, regional_ref, mes_ref)
                for mapa_ref in (mapa_real_regional, mapa_tend_regional, mapa_meta_regional)
                for (canal_ref, regional_ref, indicador_ref, mes_ref) in mapa_ref.keys()
            }
            for canal_ref, regional_ref, mes_ref in sorted(canais_meses_meta_regional):
                chave_vb_meta_reg = (canal_ref, regional_ref, 'VENDA BRUTA', mes_ref)
                if float(mapa_meta_regional.get(chave_vb_meta_reg, 0.0) or 0.0) > 0:
                    continue
                meta_ativ_reg = float(mapa_meta_regional.get((canal_ref, regional_ref, 'ATIVADOS', mes_ref), 0.0) or 0.0)
                if meta_ativ_reg <= 0:
                    continue
                ratio_reg = _ratio_vb_ativado_regional_para_meta(canal_ref, regional_ref, mes_ref)
                if ratio_reg > 0:
                    mapa_meta_regional[chave_vb_meta_reg] = float(meta_ativ_reg) / float(ratio_reg)

            # Em CONTA, FAKE representa o volume vendido que nao virou Gross Liquido.
            # O calculo e feito depois dos fallbacks de orcamento para manter todos os
            # recortes (total, canal e regional) matematicamente consistentes.
            if produto_norm_ref == 'CONTA':
                for mapa_ref in (mapa_real, mapa_tend, mapa_meta):
                    chaves_canal_mes_fake = {
                        (str(canal_key).strip(), str(mes_key).strip().lower())
                        for (canal_key, indicador_key, mes_key) in mapa_ref.keys()
                        if str(indicador_key).strip() in {'VENDA BRUTA', 'ATIVADOS'}
                    }
                    for canal_fake, mes_fake in chaves_canal_mes_fake:
                        valor_vb_fake = float(mapa_ref.get((canal_fake, 'VENDA BRUTA', mes_fake), 0.0) or 0.0)
                        valor_ativ_fake = float(mapa_ref.get((canal_fake, 'ATIVADOS', mes_fake), 0.0) or 0.0)
                        mapa_ref[(canal_fake, 'FAKE', mes_fake)] = valor_vb_fake - valor_ativ_fake

                for mapa_ref in (mapa_real_regional, mapa_tend_regional, mapa_meta_regional):
                    chaves_regional_mes_fake = {
                        (
                            str(canal_key).strip(),
                            str(regional_key).strip().upper(),
                            str(mes_key).strip().lower(),
                        )
                        for (canal_key, regional_key, indicador_key, mes_key) in mapa_ref.keys()
                        if str(indicador_key).strip() in {'VENDA BRUTA', 'ATIVADOS'}
                    }
                    for canal_fake, regional_fake, mes_fake in chaves_regional_mes_fake:
                        valor_vb_fake = float(mapa_ref.get((canal_fake, regional_fake, 'VENDA BRUTA', mes_fake), 0.0) or 0.0)
                        valor_ativ_fake = float(mapa_ref.get((canal_fake, regional_fake, 'ATIVADOS', mes_fake), 0.0) or 0.0)
                        mapa_ref[(canal_fake, regional_fake, 'FAKE', mes_fake)] = valor_vb_fake - valor_ativ_fake

""".splitlines())
            saida.append(linha)
            i += 1
            continue

        if stripped.startswith("def _lookup_indicador("):
            saida.extend(novo_bloco_lookup)
            while i < len(linhas) and linhas[i].strip() != "df_num_local = pd.DataFrame(linhas_num)":
                i += 1
            continue

        if stripped == "if coluna_ref == 'CANAL':":
            saida.append(linha.replace("if coluna_ref == 'CANAL':", "if str(coluna_ref).startswith('__') or coluna_ref == 'CANAL':"))
            i += 1
            continue

        if stripped == "if coluna_ref in {'MoM', 'YoY', 'TEND vs ORC', 'YTD26 vs YTD25', 'YTD26 vs YTD_ORÇ'}:":
            saida.append(
                linha.replace(
                    "{'MoM', 'YoY'",
                    "{'MoM', 'MoM D.U.', 'YoY'",
                )
            )
            i += 1
            continue

        saida.append(linha)
        i += 1

    return "\n".join(saida) + ("\n" if block_code.endswith("\n") else "")


def render(namespace: dict[str, object]) -> None:
    block_code = _aplicar_patches_resumo_mensal_regional(
        _ajustar_ordem_performance_regional(BLOCK_CODE)
    )
    block_code = block_code.replace(
        "        def montar_resumo_mensal_ativados_por_produto(\n",
        "        @st.cache_data(show_spinner=False, ttl=3600, max_entries=8)\n"
        "        def montar_resumo_mensal_ativados_por_produto(\n",
        1,
    )

    forecast_marker = (
        '\n        with st.container():\n'
        '            st.markdown(build_visual_title_html("EVOLU'
    )
    if forecast_marker in block_code:
        bloco_antes_previsao, bloco_depois_previsao = block_code.split(
            forecast_marker, 1
        )
        execute_block(bloco_antes_previsao, namespace, 'ativados_resumo_mensal')
        if namespace.get('tab_ativados_ativa'):
            render_ml_forecast(namespace.get('build_visual_title_html'))
        block_code = (
            "with tab1:\n"
            "    if tab_ativados_ativa:"
            f"{forecast_marker}{bloco_depois_previsao}"
        )

    if _ANALISES_ATIVADOS_MARKER not in block_code:
        execute_block(block_code, namespace, 'ativados')
        return

    bloco_resumo, bloco_restante = block_code.split(_ANALISES_ATIVADOS_MARKER, 1)
    execute_block(bloco_resumo, namespace, 'ativados_resumo')

    if namespace.get('tab_ativados_ativa'):
        render_analises = namespace.get('render_bloco_analises_detalhadas_ativados')
        if callable(render_analises):
            render_analises(
                namespace.get('df_cards_base_global'),
                namespace.get('mes_selecionado_cards'),
                namespace.get('mes_anterior_cards'),
            )

    bloco_pos_analises = (
        "with tab1:\n"
        "    if tab_ativados_ativa:"
        f"{_ANALISES_ATIVADOS_MARKER}{bloco_restante}"
    )
    execute_block(bloco_pos_analises, namespace, 'ativados_pos_analises')
